```csharp
public async Task<IActionResult> GetImage(int id)
{
    var ad = await _context.Ad.FirstOrDefaultAsync(a => a.Id == id);

    if (ad != null && ad.Img != null)
    {
        // Ideally, you'd store the content type of the image as well when uploading it.
        // For simplicity, we're assuming it's a JPEG image here.
        return new FileContentResult(ad.Img, "image/jpeg");
    }

    return NotFound();
}
```

